import 'package:flutter/material.dart'; class SectionHeader extends StatelessWidget { final String title; final String? trailing; final VoidCallback? onTrailingTap; const SectionHeader({super.key, required this.title, this.trailing, this.onTrailingTap}); @override Widget build(BuildContext context) => Padding(padding:const EdgeInsets.symmetric(vertical:12), child:Row(mainAxisAlignment:MainAxisAlignment.spaceBetween, children:[Text(title,style:const TextStyle(fontSize:12,fontWeight:FontWeight.w800,color:Color(0xFF94A3B8),letterSpacing:0.5)),if(trailing!=null)GestureDetector(onTap:onTrailingTap,child:Text(trailing!,style:const TextStyle(fontSize:12,fontWeight:FontWeight.w600,color:Color(0xFF6366F1))))])); }
